#include <stdio.h>
#include <stdint.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int64_t ans = 0;
        for (int C = 1; C <= N; ++C) {
            int maxK = N / C;
            for (int k = 2; k <= maxK; ++k) {
                int B = k * C;
                ans += (int64_t)((N - C) / B) + 1;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

